code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T, N, R;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &R);
        double result = N * (1.0 / N);
        printf("%.5f\n", result);
    }
    return 0;
}

